/* ── ADMIN URL HELPERS ── */
const D = window.pkwtDashboard || {};
const adminUrl = (path = '') => (D.adminUrl || '/wp-admin/') + path;
const siteUrl = (path = '') => (D.siteUrl || '/') + path;
